@page "/recipes/{CuisineId:int}"
@using sv_1a56f112391b4636b56affca109a0467.Services
@using Microsoft.AspNetCore.Components.Routing
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <h3>Recipes for Cuisine @CuisineId (@_sortOrder)</h3>
    <ul>
        @foreach (var recipe in GetSortedRecipes())
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private string _sortOrder = "newest";

    private int _lastLoadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        _sortOrder = string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? "popular"
            : "newest";

        // Only reload data when the cuisine actually changes
        if (CuisineId == _lastLoadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        var cuisineToLoad = CuisineId;

        // Determine loading state: first load vs refresh
        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        _error = null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineToLoad, token);

            // Only apply results if not cancelled
            if (!token.IsCancellationRequested)
            {
                _recipes = results;
                _lastLoadedCuisineId = cuisineToLoad;
                _isRefreshing = false;
            }
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineToLoad);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineToLoad);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return new();

        return _sortOrder == "popular"
            ? _recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
            : _recipes.OrderByDescending(r => r.Id).ToList();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

